script:
function filterTable() {
  var input, filter, table, tr, td, i, txtValue;
  input = document.getElementById("myInput");
  filter = input.value.toUpperCase();
  table = document.getElementById("myTable");
  tr = table.getElementsByTagName("tr");

  for (i = 0; i < tr.length; i++) {
    td = tr[i].getElementsByTagName("td")[0]; // Assuming filtering by the first column
    if (td) {
      txtValue = td.textContent || td.innerText;
      if (txtValue.toUpperCase().indexOf(filter) > -1) {
        tr[i].style.display = "";
      } else {
        tr[i].style.display = "none";
      }
    }
  }
}

// Global variables to store all data and current filters
let allSalesOrders = [];
let currentFilters = {
    customer: '',
    sales_order: '',
    date_from: '',
    date_to: ''
};

// Main function to fetch and display pending invoice sales orders (initial load)
function fetchAllSalesOrders() {
    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "Sales Order",
            filters: {
                // Only show orders that need invoicing
                status: ['in', ["To Deliver and Bill", "To Bill"]],
                // Exclude fully billed orders
                per_billed: ['<', 100]
            },
            fields: [
                "name", 
                "customer", 
                "status", 
                "delivery_date", 
                "grand_total", 
                "currency",
                "total_qty",
                "per_billed",
                "billing_status"
            ],
            order_by: "delivery_date asc"
        },
        callback: function (response) {
            if (response.message) {
                allSalesOrders = response.message;
                createFilterControls();
                populatePendingInvoiceTable(response.message);
            } else {
                console.error("No pending invoice sales orders found.");
                // Clear table and filters if no data
                createFilterControls();
                populatePendingInvoiceTable([]);
            }
        },
        error: function (xhr, status, error) {
            console.error("Error fetching pending invoice sales orders:", error);
        },
    });
}

// Call fetchAllSalesOrders initially to load data and display UI
fetchAllSalesOrders();

// Function to create filter controls
function createFilterControls() {
    var container = root_element.querySelector("#sales_order_table").parentNode;
    var existingFilters = container.querySelector(".filter-container");
    if (existingFilters) {
        existingFilters.remove();
    }

    // Get unique customers for dropdown
    var customers = [...new Set(allSalesOrders.map(order => order.customer).filter(c => c))].sort();
    var customerOptions = '<option value="" selected>All Customers</option>';
    customers.forEach(customer => {
        customerOptions += `<option value="${customer}">${customer}</option>`;
    });

    // Get unique sales orders for dropdown
    var salesOrders = [...new Set(allSalesOrders.map(order => order.name))].sort();
    var salesOrderOptions = '<option value="" selected>All Sales Orders</option>';
    salesOrders.forEach(salesOrder => {
        salesOrderOptions += `<option value="${salesOrder}">${salesOrder}</option>`;
    });

    var filterDiv = document.createElement("div");
    filterDiv.className = "filter-container";
    filterDiv.style.cssText = "display: flex; flex-wrap: wrap; gap: 15px; background: #f8f9fa; border: 1px solid #dee2e6; padding: 15px; margin-bottom: 15px; border-radius: 6px; align-items: end;";

    filterDiv.innerHTML = `
        <span>
            <label for="customer_filter">Customer:</label>
            <select id="customer_filter" class="form-control">
                ${customerOptions}
            </select>
        </span>
        <span>
            <label for="sales_order_filter">Sales Order:</label>
            <select id="sales_order_filter" class="form-control">
                ${salesOrderOptions}
            </select>
        </span>
        <span>
            <label for="date_from_filter">Date From:</label>
            <input type="date" id="date_from_filter" class="form-control">
        </span>
        <span>
            <label for="date_to_filter">Date To:</label>
            <input type="date" id="date_to_filter" class="form-control">
        </span>
        <span>
            <button id="clear_filter_btn" class="btn btn-secondary btn-sm" style="margin-top: 20px;">
                <i class="fa fa-times"></i> Clear All
            </button>
        </span>
        <span>
            <button id="apply_filter_btn" class="btn btn-primary btn-sm" style="margin-top: 20px;">
                <i class="fa fa-filter"></i> Apply Filter
            </button>
        </span>
        <div id="filter_summary" style="width: 100%; margin-top: 10px; font-size: 12px; color: #6c757d;"></div>
    `;

    container.insertBefore(filterDiv, container.firstChild);
    updateFilterSummary();

    // Attach event listeners immediately after adding to DOM
    attachFilterEventListeners();
}

// Separate function to attach event listeners
function attachFilterEventListeners() {
    var clearBtn = document.getElementById("clear_filter_btn");
    var applyBtn = document.getElementById("apply_filter_btn");

    if (clearBtn) {
        clearBtn.removeEventListener("click", clearAllFilters);
        clearBtn.addEventListener("click", clearAllFilters);
    }

    if (applyBtn) {
        applyBtn.removeEventListener("click", applyFilters);
        applyBtn.addEventListener("click", applyFilters);
    }
}

// Function to apply filters by calling backend with filter parameters
function applyFilters() {
    console.log("Apply filter button clicked"); // Debug log

    var customerFilter = document.getElementById('customer_filter');
    var salesOrderFilter = document.getElementById('sales_order_filter');
    var dateFromFilter = document.getElementById('date_from_filter');
    var dateToFilter = document.getElementById('date_to_filter');

    if (!customerFilter || !salesOrderFilter || !dateFromFilter || !dateToFilter) {
        console.error("Filter elements not found");
        return;
    }

    // Update currentFilters for summary display
    currentFilters.customer = customerFilter.value;
    currentFilters.sales_order = salesOrderFilter.value;
    currentFilters.date_from = dateFromFilter.value;
    currentFilters.date_to = dateToFilter.value;

    console.log("Applying filters:", currentFilters);

    // Prepare filters object for frappe call
    var filters = {
        status: ['in', ["To Deliver and Bill", "To Bill"]],
        per_billed: ['<', 100]
    };

    if (currentFilters.customer) {
        filters.customer = currentFilters.customer;
    }
    if (currentFilters.sales_order) {
        filters.name = currentFilters.sales_order;
    }
    if (currentFilters.date_from) {
        filters.delivery_date = filters.delivery_date || {};
        filters.delivery_date['>='] = currentFilters.date_from;
    }
    if (currentFilters.date_to) {
        filters.delivery_date = filters.delivery_date || {};
        filters.delivery_date['<='] = currentFilters.date_to;
    }

    // Call backend with filters to get filtered sales orders
    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "Sales Order",
            filters: filters,
            fields: [
                "name",
                "customer",
                "status",
                "delivery_date",
                "grand_total",
                "currency",
                "total_qty",
                "per_billed",
                "billing_status"
            ],
            order_by: "delivery_date asc",
            limit_page_length: 100
        },
        callback: function(response) {
            if (response.message) {
                allSalesOrders = response.message;
                updateFilterSummary();
                populatePendingInvoiceTable(response.message);

                console.log("Filtered sales orders count:", response.message.length);
                console.log("Filtered sales orders:", response.message);
            } else {
                console.log("No sales orders found with these filters");
                allSalesOrders = [];
                updateFilterSummary();
                populatePendingInvoiceTable([]);
            }
        },
        error: function(err) {
            console.error("Error fetching filtered sales orders:", err);
        }
    });
}

// Function to update filter summary display
function updateFilterSummary() {
    var summaryElement = document.getElementById('filter_summary');
    if (!summaryElement) return;

    var activeFilters = [];
    if (currentFilters.customer) activeFilters.push(`Customer: ${currentFilters.customer}`);
    if (currentFilters.sales_order) activeFilters.push(`Sales Order: ${currentFilters.sales_order}`);
    if (currentFilters.date_from) {
        var fromDate = currentFilters.date_from;
        if (typeof frappe !== 'undefined' && frappe.datetime && frappe.datetime.str_to_user) {
            fromDate = frappe.datetime.str_to_user(currentFilters.date_from);
        }
        activeFilters.push(`From: ${fromDate}`);
    }
    if (currentFilters.date_to) {
        var toDate = currentFilters.date_to;
        if (typeof frappe !== 'undefined' && frappe.datetime && frappe.datetime.str_to_user) {
            toDate = frappe.datetime.str_to_user(currentFilters.date_to);
        }
        activeFilters.push(`To: ${toDate}`);
    }

    if (activeFilters.length > 0) {
        summaryElement.innerHTML = '<strong>Active Filters:</strong> ' + activeFilters.join(' | ');
    } else {
        summaryElement.innerHTML = 'No filters applied - showing all pending invoice orders';
    }
}

// Function to clear all filters and reload all data from backend
function clearAllFilters() {
    console.log("Clear all filters clicked"); // Debug log

    // Reset current filters
    currentFilters = {
        customer: '',
        sales_order: '',
        date_from: '',
        date_to: ''
    };

    // Reset UI inputs
    var customerFilter = document.getElementById('customer_filter');
    var salesOrderFilter = document.getElementById('sales_order_filter');
    var dateFromFilter = document.getElementById('date_from_filter');
    var dateToFilter = document.getElementById('date_to_filter');

    if (customerFilter) customerFilter.value = '';
    if (salesOrderFilter) salesOrderFilter.value = '';
    if (dateFromFilter) dateFromFilter.value = '';
    if (dateToFilter) dateToFilter.value = '';

    // Reload all data from server (no filters)
    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "Sales Order",
            filters: {
                status: ['in', ["To Deliver and Bill", "To Bill"]],
                per_billed: ['<', 100]
            },
            fields: [
                "name",
                "customer",
                "status",
                "delivery_date",
                "grand_total",
                "currency",
                "total_qty",
                "per_billed",
                "billing_status"
            ],
            order_by: "delivery_date asc",
            limit_page_length: 100
        },
        callback: function(response) {
            if (response.message) {
                allSalesOrders = response.message;
                updateFilterSummary();
                populatePendingInvoiceTable(response.message);
            } else {
                console.log("No sales orders found.");
                allSalesOrders = [];
                updateFilterSummary();
                populatePendingInvoiceTable([]);
            }
        },
        error: function(err) {
            console.error("Error clearing filters / fetching all data:", err);
        }
    });

    if (typeof frappe !== 'undefined' && frappe.show_alert) {
        frappe.show_alert({
            message: __('All filters cleared'),
            indicator: 'blue'
        }, 2);
    } else {
        console.log('All filters cleared');
    }
}

// Function to format currency (dummy; use frappe's, if available)
function format_currency(amount, currency) {
    if (typeof frappe !== "undefined" && frappe && frappe.format) {
        return frappe.format(amount, {fieldtype:'Currency'}, {currency: currency});
    }
    // fallback basic formatting
    return (currency || '') + ' ' + (amount || 0).toLocaleString(undefined, {minimumFractionDigits: 2});
}

// Function to populate the table with pending invoice data
function populatePendingInvoiceTable(sales_orders) {
    console.log("Populating table with", sales_orders.length, "orders"); // Debug log

    var salesOrderTable = root_element.querySelector("#sales_order_table");
    if (!salesOrderTable) {
        console.error("Sales order table not found");
        return;
    }

    var tableHTML = "<thead><tr><th>Sales Order ID</th><th>Customer</th><th>Status</th><th>Delivery Date</th><th>Pending Amount</th><th>Pending Qty</th><th>Action</th></tr></thead>";
    tableHTML += "<tbody>";

    sales_orders.forEach(function (sales_order) {
        tableHTML += "<tr>";
        tableHTML += "<td><a href='/app/sales-order/" + sales_order.name + "'>" + sales_order.name + "</a></td>";
        tableHTML += "<td>" + (sales_order.customer || '') + "</td>";

        var statusColor = "";
        switch(sales_order.status) {
            case "To Deliver and Bill":
                statusColor = "red";
                break;
            case "To Bill":
                statusColor = "orange";
                break;
            default:
                statusColor = "inherit";
        }
        tableHTML += "<td style='color: " + statusColor + "; font-weight: bold;'>" + sales_order.status + "</td>";

        var deliveryDate = sales_order.delivery_date ? 
            (typeof frappe !== 'undefined' && frappe.datetime && frappe.datetime.str_to_user ? 
             frappe.datetime.str_to_user(sales_order.delivery_date) : sales_order.delivery_date) : '-';
        var deliveryDateColor = "inherit";
        if (sales_order.delivery_date) {
            var today = new Date();
            var dueDate = new Date(sales_order.delivery_date);
            today.setHours(0,0,0,0);
            dueDate.setHours(0,0,0,0);
            if (dueDate < today) {
                deliveryDateColor = "red";
            } else if ((dueDate - today) / (1000 * 60 * 60 * 24) <= 7) {
                deliveryDateColor = "orange";
            }
        }
        tableHTML += "<td style='color: " + deliveryDateColor + "; font-weight: bold;'>" + deliveryDate + "</td>";

        var billedPercentage = sales_order.per_billed || 0;
        var pendingAmount = sales_order.grand_total ? 
            (sales_order.grand_total * (100 - billedPercentage)) / 100 : 0;
        var formattedPendingAmount = format_currency(pendingAmount, sales_order.currency);
        tableHTML += "<td style='color: red; font-weight: bold; font-size: 14px;'>" + formattedPendingAmount + "</td>";

        var totalQty = sales_order.total_qty || 0;
        var billedQty = (totalQty * billedPercentage) / 100;
        var remainingQty = totalQty - billedQty;
        tableHTML += "<td style='color: red; font-weight: bold;'>" + remainingQty.toFixed(2) + "</td>";

        tableHTML += "<td><a href='/app/sales-order/" + sales_order.name + "' class='btn btn-info btn-xs' style='font-size: 11px; text-decoration: none; color: white;'>View</a></td>";
        tableHTML += "</tr>";
    });

    tableHTML += "</tbody>";
    salesOrderTable.innerHTML = tableHTML;

    addPendingInvoiceSummary(sales_orders);
}

// Function to add summary information at the top
function addPendingInvoiceSummary(sales_orders) {
    var totalPendingAmount = 0;
    var totalPendingQty = 0;
    var overdueCount = 0;

    sales_orders.forEach(function(order) {
        var billedPercentage = order.per_billed || 0;
        var pendingAmount = order.grand_total ? 
            (order.grand_total * (100 - billedPercentage)) / 100 : 0;
        totalPendingAmount += pendingAmount;

        var totalQty = order.total_qty || 0;
        var billedQty = (totalQty * billedPercentage) / 100;
        totalPendingQty += (totalQty - billedQty);

        if (order.delivery_date) {
            var today = new Date();
            var dueDate = new Date(order.delivery_date);
            today.setHours(0,0,0,0);
            dueDate.setHours(0,0,0,0);
            if (dueDate < today) {
                overdueCount++;
            }
        }
    });

    var container = root_element.querySelector("#sales_order_table").parentNode;
    var existingSummary = container.querySelector(".pending-invoice-summary");
    if (existingSummary) {
        existingSummary.remove();
    }

    var summaryDiv = document.createElement("div");
    summaryDiv.className = "pending-invoice-summary";
    summaryDiv.style.cssText = "background: #fff3cd; border: 1px solid #ffeaa7; padding: 10px; margin-bottom: 10px; border-radius: 4px;";

    // summaryDiv.innerHTML = 
    //     "<h5 style='margin: 0 0 5px 0; color: #856404;'>📋 Pending Invoices Summary</h5>" +
    //     "<div style='display: flex; gap: 20px; font-size: 13px;'>" +
    //         "<span><strong>Total Orders:</strong> " + sales_orders.length + "</span>" +
    //         "<span><strong>Overdue:</strong> <span style='color: red;'>" + overdueCount + "</span></span>" +
    //         "<span><strong>Pending Amount:</strong> <span style='color: red; font-weight: bold;'>" + 
    //             format_currency(totalPendingAmount, sales_orders[0]?.currency || 'INR') + "</span></span>" +
    //         "<span><strong>Pending Qty:</strong> <span style='color: red;'>" + totalPendingQty.toFixed(2) + "</span></span>" +
    //     "</div>";

    // container.insertBefore(summaryDiv, container.firstChild);
}

'use strict';

    // Global variables to store all data and current filters
    let today = new Date().toISOString().split('T')[0];
    let allSalesOrders = [];
    let filteredSalesOrders = [];
    let currentFilters = {
        customer: '',
        sales_order: '',
        sales_person: '',
        date_from: '',
        date_to: ''
    };

    // Set default date filter values: both from and to as today's date
    const dateFromFilter = safeGetElement('date_from_filter');
    const dateToFilter = safeGetElement('date_to_filter');
    if (dateFromFilter) dateFromFilter.value = today;
    if (dateToFilter) dateToFilter.value = today;

    // Also update currentFilters in JS
    currentFilters.date_from = today;
    currentFilters.date_to = today;

    let isInitialized = false;

    // Utility function to safely get element using root_element
    function safeGetElement(id) {
        const element = root_element.querySelector('#' + id);
        if (!element) {
            console.warn(`Element with id '${id}' not found in root_element`);
        }
        return element;
    }

    // Utility function to safely set content
    function safeSetContent(id, content) {
        const element = safeGetElement(id);
        if (element) {
            element.innerHTML = content;
        }
        return element;
    }

    // Utility function to safely set style
    function safeSetStyle(id, property, value) {
        const element = safeGetElement(id);
        if (element && element.style) {
            element.style[property] = value;
        }
        return element;
    }

    // Check if frappe is available
    function checkFrappeAvailability() {
        if (typeof frappe === 'undefined') {
            safeSetContent('loading_message', 
                '<div class="error-message">Error: Frappe framework not available. Please ensure this is running in a Frappe environment.</div>');
            return false;
        }
        return true;
    }

    // Function to show loading state
    function showLoading() {
        safeSetStyle('loading_message', 'display', 'block');
        safeSetStyle('sales_order_table', 'display', 'none');
        safeSetStyle('error_message', 'display', 'none');
    }

    // Function to hide loading state
    function hideLoading() {
        safeSetStyle('loading_message', 'display', 'none');
        safeSetStyle('sales_order_table', 'display', 'table');
    }

    // Function to show error message
    function showError(message) {
        safeSetContent('error_message', message);
        safeSetStyle('error_message', 'display', 'block');
        safeSetStyle('sales_order_table', 'display', 'none');
    }

    // Function to show no data message
    function showNoData(message) {
        safeSetContent('sales_order_tbody', 
            `<tr><td colspan="8" class="no-data">${message}</td></tr>`);
        safeSetStyle('sales_order_table', 'display', 'table');
    }

    // Main function to fetch and display pending invoice sales orders
    function fetchAllSalesOrders() {
        if (!checkFrappeAvailability()) {
            return;
        }

        console.log('Fetching sales orders...');
        showLoading();

        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Sales Order",
                filters: {
                    // Only show orders that need invoicing
                    status: ['in', ["To Deliver and Bill", "To Bill"]],
                    // Exclude fully billed orders
                    per_billed: ['<', 100]
                },
                fields: [
                    "name", 
                    "customer", 
                    "custom_sales_person",
                    "status", 
                    "delivery_date", 
                    "grand_total", 
                    "currency",
                    "total_qty",
                    "per_billed",
                    "billing_status",
                    "transaction_date"
                ],
                order_by: "delivery_date asc",
                limit_page_length: 0  // Get all records
            },
            callback: function (response) {
                console.log('API Response:', response);
                hideLoading();

                if (response.message && Array.isArray(response.message) && response.message.length > 0) {
                    allSalesOrders = response.message;
                    filteredSalesOrders = [...allSalesOrders];
                    populateFilterDropdowns();
                    populatePendingInvoiceTable(filteredSalesOrders);
                    console.log("Loaded", allSalesOrders.length, "sales orders");
                } else {
                    console.log('No sales orders found');
                    allSalesOrders = [];
                    filteredSalesOrders = [];
                    populateFilterDropdowns();
                    showNoData("No pending invoice sales orders found");
                }
                updateFilterSummary();
            },
            error: function (xhr, status, error) {
                hideLoading();
                console.error("Error fetching sales orders:", error, xhr);
                showError("Failed to load sales orders. Please refresh the page and try again.");
            }
        });
    }

    // Function to populate filter dropdowns
    function populateFilterDropdowns() {
        // Populate customer dropdown
        const customerFilter = safeGetElement('customer_filter');
        if (customerFilter) {
            const customers = [...new Set(allSalesOrders.map(order => order.customer).filter(c => c))].sort();

            customerFilter.innerHTML = '<option value="">All Customers</option>';
            customers.forEach(customer => {
                customerFilter.innerHTML += `<option value="${customer}">${customer}</option>`;
            });
            console.log('Populated customer dropdown with', customers.length, 'customers');
        }

        // Populate sales order dropdown
        const salesOrderFilter = safeGetElement('sales_order_filter');
        if (salesOrderFilter) {
            const salesOrders = [...new Set(allSalesOrders.map(order => order.name))].sort();

            salesOrderFilter.innerHTML = '<option value="">All Sales Orders</option>';
            salesOrders.forEach(salesOrder => {
                salesOrderFilter.innerHTML += `<option value="${salesOrder}">${salesOrder}</option>`;
            });
            console.log('Populated sales order dropdown with', salesOrders.length, 'orders');
        }

        // Populate sales person dropdown
        const salesPersonFilter = safeGetElement('sales_person_filter');
        if (salesPersonFilter) {
            const salesPersons = [...new Set(allSalesOrders.map(order => order.custom_sales_person).filter(sp => sp))].sort();

            salesPersonFilter.innerHTML = '<option value="">All Sales Persons</option>';
            salesPersons.forEach(salesPerson => {
                salesPersonFilter.innerHTML += `<option value="${salesPerson}">${salesPerson}</option>`;
            });
            console.log('Populated sales person dropdown with', salesPersons.length, 'sales persons');
        }
    }

    // Function to apply filters
    function applyFilters() {
        if (!checkFrappeAvailability()) {
            return;
        }

        console.log("Applying filters...");

        // Update current filters from DOM
        updateCurrentFiltersFromDOM();
        console.log("Current filters:", currentFilters);

        // Show loading in table
        safeSetContent('sales_order_tbody', 
            '<tr><td colspan="8" style="text-align: center; padding: 20px;">Applying filters...</td></tr>');

        // Prepare filters object for frappe call
        let filters = {
            status: ['in', ["To Deliver and Bill", "To Bill"]],
            per_billed: ['<', 100]
        };

        if (currentFilters.customer) {
            filters.customer = currentFilters.customer;
        }
        if (currentFilters.sales_order) {
            filters.name = currentFilters.sales_order;
        }
        if (currentFilters.sales_person) {
            filters.custom_sales_person = currentFilters.sales_person;
        }

        // Handle date filtering properly to avoid NULL date issues
        if (currentFilters.date_from && currentFilters.date_to) {
            // Both from and to dates provided
            filters.delivery_date = ['between', [currentFilters.date_from, currentFilters.date_to]];
        } else if (currentFilters.date_from) {
            // Only from date provided
            filters.delivery_date = ['>=', currentFilters.date_from];
        } else if (currentFilters.date_to) {
            // Only to date provided
            filters.delivery_date = ['<=', currentFilters.date_to];
        }

        console.log('Applying filters:', filters);

        // Use a simpler approach to handle NULL dates - filter them out client-side
        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Sales Order",
                filters: filters,
                fields: [
                    "name", 
                    "customer", 
                    "custom_sales_person",
                    "status", 
                    "delivery_date",
                    "grand_total", 
                    "currency", 
                    "total_qty", 
                    "per_billed", 
                    "billing_status",
                    "transaction_date"
                ],
                order_by: "delivery_date asc",
                limit_page_length: 0
            },
            callback: function(response) {
                console.log('Filter API Response:', response);
                if (response.message && Array.isArray(response.message)) {
                    let results = response.message;

                    // If date filtering is applied, filter out NULL delivery_date records client-side
                    if (currentFilters.date_from || currentFilters.date_to) {
                        results = results.filter(order => {
                            // Exclude orders with null or empty delivery_date when date filtering
                            return order.delivery_date && order.delivery_date !== null && order.delivery_date !== '';
                        });
                    }

                    filteredSalesOrders = results;
                    populatePendingInvoiceTable(filteredSalesOrders);
                    updateFilterSummary();
                    console.log("Filtered sales orders count:", results.length);

                    if (frappe.show_alert) {
                        frappe.show_alert({
                            message: `Filter applied. Found ${results.length} orders.`,
                            indicator: 'green'
                        }, 3);
                    }
                } else {
                    console.log("No sales orders found with these filters");
                    filteredSalesOrders = [];
                    showNoData("No sales orders found with current filters");
                    updateFilterSummary();

                    if (frappe.show_alert) {
                        frappe.show_alert({
                            message: 'No orders found with current filters',
                            indicator: 'orange'
                        }, 3);
                    }
                }
            },
            error: function(err) {
                console.error("Error fetching filtered sales orders:", err);
                showError("Error applying filters. Please try again.");
                if (frappe.show_alert) {
                    frappe.show_alert({
                        message: 'Error applying filters',
                        indicator: 'red'
                    }, 3);
                }
            }
        });
    }

    // Function to clear all filters
    function clearAllFilters() {
        console.log("Clearing all filters...");

        // Reset current filters
        currentFilters = {
            customer: '',
            sales_order: '',
            sales_person: '',
            date_from: '',
            date_to: ''
        };

        // Reset UI inputs
        const customerFilter = safeGetElement('customer_filter');
        const salesOrderFilter = safeGetElement('sales_order_filter');
        const salesPersonFilter = safeGetElement('sales_person_filter');
        const dateFromFilter = safeGetElement('date_from_filter');
        const dateToFilter = safeGetElement('date_to_filter');

        if (customerFilter) customerFilter.value = '';
        if (salesOrderFilter) salesOrderFilter.value = '';
        if (salesPersonFilter) salesPersonFilter.value = '';
        if (dateFromFilter) dateFromFilter.value = '';
        if (dateToFilter) dateToFilter.value = '';

        // Show all original data
        filteredSalesOrders = [...allSalesOrders];
        populatePendingInvoiceTable(filteredSalesOrders);
        updateFilterSummary();

        if (frappe.show_alert) {
            frappe.show_alert({
                message: 'All filters cleared',
                indicator: 'blue'
            }, 2);
        }
    }

    // Helper function to update current filters from DOM
    function updateCurrentFiltersFromDOM() {
        const customerFilter = safeGetElement('customer_filter');
        const salesOrderFilter = safeGetElement('sales_order_filter');
        const salesPersonFilter = safeGetElement('sales_person_filter');
        const dateFromFilter = safeGetElement('date_from_filter');
        const dateToFilter = safeGetElement('date_to_filter');

        if (customerFilter) currentFilters.customer = customerFilter.value;
        if (salesOrderFilter) currentFilters.sales_order = salesOrderFilter.value;
        if (salesPersonFilter) currentFilters.sales_person = salesPersonFilter.value;
        if (dateFromFilter) currentFilters.date_from = dateFromFilter.value;
        if (dateToFilter) currentFilters.date_to = dateToFilter.value;
    }

    // Function to update filter summary display
    function updateFilterSummary() {
        const summaryElement = safeGetElement('filter_summary');
        if (!summaryElement) return;

        const activeFilters = [];
        if (currentFilters.customer) activeFilters.push(`Customer: ${currentFilters.customer}`);
        if (currentFilters.sales_order) activeFilters.push(`Sales Order: ${currentFilters.sales_order}`);
        if (currentFilters.sales_person) activeFilters.push(`Sales Person: ${currentFilters.sales_person}`);
        if (currentFilters.date_from) {
            let fromDate = currentFilters.date_from;
            if (frappe && frappe.datetime && frappe.datetime.str_to_user) {
                fromDate = frappe.datetime.str_to_user(currentFilters.date_from);
            }
            activeFilters.push(`From: ${fromDate}`);
        }
        if (currentFilters.date_to) {
            let toDate = currentFilters.date_to;
            if (frappe && frappe.datetime && frappe.datetime.str_to_user) {
                toDate = frappe.datetime.str_to_user(currentFilters.date_to);
            }
            activeFilters.push(`To: ${toDate}`);
        }

        if (activeFilters.length > 0) {
            summaryElement.innerHTML = '<strong>Active Filters:</strong> ' + activeFilters.join(' | ');
        } else {
            summaryElement.innerHTML = 'No filters applied - showing all pending invoice orders';
        }
    }

    // Function to format currency using Frappe's formatting
    function format_currency(amount, currency) {
        if (frappe && frappe.format) {
            try {
                return frappe.format(amount, {fieldtype:'Currency'}, {currency: currency});
            } catch(e) {
                console.warn('Error formatting currency:', e);
            }
        }
        // Fallback formatting
        const symbol = currency === 'INR' ? '₹' : (currency || '');
        return `${symbol} ${(amount || 0).toLocaleString(undefined, {minimumFractionDigits: 2})}`;
    }

    // Function to populate the table with pending invoice data
    function populatePendingInvoiceTable(sales_orders) {
        console.log("Populating table with", sales_orders.length, "orders");

        const tbody = safeGetElement('sales_order_tbody');
        if (!tbody) {
            console.error("Sales order table body not found in root_element");
            return;
        }

        if (sales_orders.length === 0) {
            tbody.innerHTML = "<tr><td colspan='8' class='no-data'>No sales orders found with current filters</td></tr>";
            safeSetStyle('sales_order_table', 'display', 'table');
        } else {
            let tableHTML = "";

            sales_orders.forEach(function (sales_order) {
                tableHTML += "<tr>";

                // Sales Order ID with link
                tableHTML += `<td><a href='/app/sales-order/${sales_order.name}' target='_blank'>${sales_order.name}</a></td>`;

                // Customer
                tableHTML += `<td>${sales_order.customer || '-'}</td>`;

                // Sales Person
                tableHTML += `<td>${sales_order.custom_sales_person || '-'}</td>`;

                // Status with color coding
                let statusColor = "";
                switch(sales_order.status) {
                    case "To Deliver and Bill":
                        statusColor = "Black";
                        break;
                    case "To Bill":
                        statusColor = "Black";
                        break;
                    default:
                        statusColor = "Black";
                }
                tableHTML += `<td style='color: ${statusColor}; font-weight: bold;'>${sales_order.status}</td>`;

                // Delivery Date with overdue highlighting
                let deliveryDate = '-';
                let deliveryDateColor = "#495057";

                if (sales_order.delivery_date) {
                    deliveryDate = sales_order.delivery_date;
                    if (frappe && frappe.datetime && frappe.datetime.str_to_user) {
                        try {
                            deliveryDate = frappe.datetime.str_to_user(sales_order.delivery_date);
                        } catch(e) {
                            console.warn('Error formatting date:', e);
                        }
                    }

                    const today = new Date();
                    const dueDate = new Date(sales_order.delivery_date);
                    today.setHours(0,0,0,0);
                    dueDate.setHours(0,0,0,0);
                    if (dueDate < today) {
                        deliveryDateColor = "#dc3545"; // Red for overdue
                    } else if ((dueDate - today) / (1000 * 60 * 60 * 24) <= 7) {
                        deliveryDateColor = "#fd7e14"; // Orange for due soon
                    }
                }
                tableHTML += `<td style='color: ${deliveryDateColor}; font-weight: bold;'>${deliveryDate}</td>`;

                // Pending Amount
                const billedPercentage = sales_order.per_billed || 0;
                const pendingAmount = sales_order.grand_total ? 
                    (sales_order.grand_total * (100 - billedPercentage)) / 100 : 0;
                const formattedPendingAmount = format_currency(pendingAmount, sales_order.currency);
                tableHTML += `<td style='color: Black; font-weight: bold; font-size: 14px; text-align: center;'>${formattedPendingAmount}</td>`;

                // Pending Quantity
                const totalQty = sales_order.total_qty || 0;
                const billedQty = (totalQty * billedPercentage) / 100;
                const remainingQty = totalQty - billedQty;
                tableHTML += `<td style='color: Black; font-weight: bold; text-align: center;'>${remainingQty.toFixed(2)}</td>`;

                // Action
                tableHTML += `<td><a href='/app/sales-order/${sales_order.name}' class='btn btn-info' target='_blank'>View</a></td>`;
                tableHTML += "</tr>";
            });

            tbody.innerHTML = tableHTML;
            safeSetStyle('sales_order_table', 'display', 'table');
            console.log("Table populated successfully");
        }

        // Add summary
        addPendingInvoiceSummary(sales_orders);
    }

    // Function to add summary information
    function addPendingInvoiceSummary(sales_orders) {
        let totalPendingAmount = 0;
        let totalPendingQty = 0;
        let overdueCount = 0;
        let defaultCurrency = 'INR';

        sales_orders.forEach(function(order) {
            const billedPercentage = order.per_billed || 0;
            const pendingAmount = order.grand_total ? 
                (order.grand_total * (100 - billedPercentage)) / 100 : 0;
            totalPendingAmount += pendingAmount;

            const totalQty = order.total_qty || 0;
            const billedQty = (totalQty * billedPercentage) / 100;
            totalPendingQty += (totalQty - billedQty);

            if (order.currency) {
                defaultCurrency = order.currency;
            }

            if (order.delivery_date) {
                const today = new Date();
                const dueDate = new Date(order.delivery_date);
                today.setHours(0,0,0,0);
                dueDate.setHours(0,0,0,0);
                if (dueDate < today) {
                    overdueCount++;
                }
            }
        });
    }

    // Initialize the dashboard when DOM is ready
    function initializeDashboard() {
        if (isInitialized) {
            console.log('Dashboard already initialized');
            return;
        }

        console.log('Initializing dashboard...');

        // Check if root_element is available
        if (typeof root_element === 'undefined') {
            console.error('root_element is not available');
            return;
        }

        console.log('root_element found:', root_element);

        // Wait a bit for DOM to be fully ready
        setTimeout(function() {
            // Attach event listeners
            const applyBtn = safeGetElement('apply_filter_btn');
            const clearBtn = safeGetElement('clear_filter_btn');

            if (applyBtn) {
                applyBtn.addEventListener('click', applyFilters);
                console.log('Apply button event listener attached');
            }

            if (clearBtn) {
                clearBtn.addEventListener('click', clearAllFilters);
                console.log('Clear button event listener attached');
            }

            // Add change event listeners for real-time filter summary updates
            const filterElements = ['customer_filter', 'sales_order_filter', 'sales_person_filter', 'date_from_filter', 'date_to_filter'];
            filterElements.forEach(id => {
                const element = safeGetElement(id);
                if (element) {
                    element.addEventListener('change', function() {
                        updateCurrentFiltersFromDOM();
                        updateFilterSummary();
                    });
                    console.log(`Change event listener attached for ${id}`);
                }
            });

            isInitialized = true;
            console.log('Dashboard initialized successfully');

            // Load initial data
            fetchAllSalesOrders();
        }, 500); // Wait 500ms for DOM to be fully ready
    }

    // Multiple initialization attempts to handle different loading states
    function attemptInitialization() {
        console.log('Attempting initialization, document state:', document.readyState);

        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', initializeDashboard);
        } else {
            initializeDashboard();
        }

        // Also try after a delay in case DOM isn't fully ready
        setTimeout(initializeDashboard, 1000);
    }

    // Start initialization
    attemptInitialization();

