script:
'use strict';

    // Global variables to store all data and current filters
    let today = new Date().toISOString().split('T')[0];
    let allSalesOrders = [];
    let allSalesOrderItems = [];
    let filteredSalesOrders = [];
    let currentFilters = {
        customer: '',
        sales_order: '',
        sales_person: '',
        item: '',
        date_from: '',
        date_to: ''
    };

    // Set default date filter values: both from and to as today's date
    const dateFromFilter = safeGetElement('date_from_filter');
    const dateToFilter = safeGetElement('date_to_filter');
    if (dateFromFilter) dateFromFilter.value = today;
    if (dateToFilter) dateToFilter.value = today;

    // Also update currentFilters in JS
    currentFilters.date_from = today;
    currentFilters.date_to = today;

    let isInitialized = false;

    // Utility function to safely get element using root_element
    function safeGetElement(id) {
        const element = root_element.querySelector('#' + id);
        if (!element) {
            console.warn(`Element with id '${id}' not found in root_element`);
        }
        return element;
    }

    // Utility function to safely set content
    function safeSetContent(id, content) {
        const element = safeGetElement(id);
        if (element) {
            element.innerHTML = content;
        }
        return element;
    }

    // Utility function to safely set style
    function safeSetStyle(id, property, value) {
        const element = safeGetElement(id);
        if (element && element.style) {
            element.style[property] = value;
        }
        return element;
    }

    // Check if frappe is available
    function checkFrappeAvailability() {
        if (typeof frappe === 'undefined') {
            safeSetContent('loading_message', 
                '<div class="error-message">Error: Frappe framework not available. Please ensure this is running in a Frappe environment.</div>');
            return false;
        }
        return true;
    }

    // Function to show loading state
    function showLoading() {
        safeSetStyle('loading_message', 'display', 'block');
        safeSetStyle('sales_order_table', 'display', 'none');
        safeSetStyle('error_message', 'display', 'none');
    }

    // Function to hide loading state
    function hideLoading() {
        safeSetStyle('loading_message', 'display', 'none');
        safeSetStyle('sales_order_table', 'display', 'table');
    }

    // Function to show error message
    function showError(message) {
        safeSetContent('error_message', message);
        safeSetStyle('error_message', 'display', 'block');
        safeSetStyle('sales_order_table', 'display', 'none');
    }

    // Function to show no data message
    function showNoData(message) {
        safeSetContent('sales_order_tbody', 
            `<tr><td colspan="10" class="no-data">${message}</td></tr>`);
        safeSetStyle('sales_order_table', 'display', 'table');
    }

    // Function to fetch sales orders with items using a custom server method
    function fetchSalesOrdersWithItems() {
        return new Promise((resolve, reject) => {
            frappe.call({
                method: "frappe.client.get_list",
                args: {
                    doctype: "Sales Order",
                    filters: {
                        status: ['in', ["To Deliver and Bill", "To Bill"]],
                        per_billed: ['<', 100]
                    },
                    fields: [
                        "name", 
                        "customer", 
                        "custom_sales_person",
                        "status", 
                        "delivery_date", 
                        "grand_total", 
                        "currency",
                        "total_qty",
                        "per_billed",
                        "billing_status",
                        "transaction_date"
                    ],
                    order_by: "delivery_date asc",
                    limit_page_length: 0
                },
                callback: function(response) {
                    if (response.message && Array.isArray(response.message)) {
                        // Now fetch items for each sales order
                        fetchItemsForSalesOrders(response.message).then(ordersWithItems => {
                            resolve(ordersWithItems);
                        }).catch(reject);
                    } else {
                        resolve([]);
                    }
                },
                error: function(err) {
                    console.error("Error fetching sales orders:", err);
                    reject(err);
                }
            });
        });
    }

    // Function to fetch items for multiple sales orders
    function fetchItemsForSalesOrders(salesOrders) {
        return new Promise((resolve, reject) => {
            if (salesOrders.length === 0) {
                resolve([]);
                return;
            }

            let completedRequests = 0;
            let allItems = [];
            const totalRequests = salesOrders.length;

            salesOrders.forEach(order => {
                frappe.call({
                    method: "frappe.client.get",
                    args: {
                        doctype: "Sales Order",
                        name: order.name
                    },
                    callback: function(response) {
                        if (response.message && response.message.items) {
                            // Filter based on billed_amt vs amount
                            const pendingItems = response.message.items.filter(item => {
                                const billedAmt = parseFloat(item.billed_amt || 0);
                                const totalAmt = parseFloat(item.amount || 0);
                                const pendingAmt = totalAmt - billedAmt;

                                // Only include items that have pending amount > 0.01 AND are not fully billed by amount
                                const hasPendingAmt = pendingAmt > 0.01;
                                const notFullyBilled = billedAmt < totalAmt;

                                console.log(`Order ${order.name}, Item ${item.item_code}: amount=${totalAmt}, billed_amt=${billedAmt}, pending_amt=${pendingAmt}, include=${hasPendingAmt && notFullyBilled}`);

                                return hasPendingAmt && notFullyBilled;
                            });

                            order.items = pendingItems;
                            console.log(`Order ${order.name}: Filtered ${response.message.items.length} items to ${pendingItems.length} pending items based on amount`);

                            // Extract unique items for filter dropdown (only pending items)
                            pendingItems.forEach(item => {
                                const existingItem = allItems.find(i => i.item_code === item.item_code);
                                if (!existingItem) {
                                    allItems.push({
                                        item_code: item.item_code,
                                        item_name: item.item_name
                                    });
                                }
                            });
                        } else {
                            order.items = [];
                        }

                        completedRequests++;
                        if (completedRequests === totalRequests) {
                            allSalesOrderItems = allItems;
                            console.log("Loaded items for", salesOrders.length, "sales orders");
                            console.log("Found", allItems.length, "unique items with pending amounts");
                            resolve(salesOrders);
                        }
                    },
                    error: function(err) {
                        console.error("Error fetching items for order", order.name, ":", err);
                        order.items = [];

                        completedRequests++;
                        if (completedRequests === totalRequests) {
                            allSalesOrderItems = allItems;
                            resolve(salesOrders);
                        }
                    }
                });
            });
        });
    }

    // Main function to fetch and display pending invoice sales orders
    function fetchAllSalesOrders() {
        if (!checkFrappeAvailability()) {
            return;
        }

        console.log('Fetching sales orders with items...');
        showLoading();

        // Fetch sales orders with their items
        fetchSalesOrdersWithItems().then(ordersWithItems => {
            console.log('API Response:', ordersWithItems);
            hideLoading();

            if (ordersWithItems && ordersWithItems.length > 0) {
                allSalesOrders = ordersWithItems;
                filteredSalesOrders = [...allSalesOrders];
                populateFilterDropdowns();
                populatePendingInvoiceTable(filteredSalesOrders);
                console.log("Loaded", allSalesOrders.length, "sales orders");
            } else {
                console.log('No sales orders found');
                allSalesOrders = [];
                filteredSalesOrders = [];
                allSalesOrderItems = [];
                populateFilterDropdowns();
                showNoData("No pending invoice sales orders found");
            }
            updateFilterSummary();
        }).catch(error => {
            hideLoading();
            console.error("Error fetching sales orders:", error);
            showError("Failed to load sales orders. Please refresh the page and try again.");
        });
    }



    // Function to populate filter dropdowns
    function populateFilterDropdowns() {
        // Populate customer dropdown
        const customerFilter = safeGetElement('customer_filter');
        if (customerFilter) {
            const customers = [...new Set(allSalesOrders.map(order => order.customer).filter(c => c))].sort();

            customerFilter.innerHTML = '<option value="">All Customers</option>';
            customers.forEach(customer => {
                customerFilter.innerHTML += `<option value="${customer}">${customer}</option>`;
            });
            console.log('Populated customer dropdown with', customers.length, 'customers');
        }

        // Populate sales order dropdown
        const salesOrderFilter = safeGetElement('sales_order_filter');
        if (salesOrderFilter) {
            const salesOrders = [...new Set(allSalesOrders.map(order => order.name))].sort();

            salesOrderFilter.innerHTML = '<option value="">All Sales Orders</option>';
            salesOrders.forEach(salesOrder => {
                salesOrderFilter.innerHTML += `<option value="${salesOrder}">${salesOrder}</option>`;
            });
            console.log('Populated sales order dropdown with', salesOrders.length, 'orders');
        }

        // Populate sales person dropdown
        const salesPersonFilter = safeGetElement('sales_person_filter');
        if (salesPersonFilter) {
            const salesPersons = [...new Set(allSalesOrders.map(order => order.custom_sales_person).filter(sp => sp))].sort();

            salesPersonFilter.innerHTML = '<option value="">All Sales Persons</option>';
            salesPersons.forEach(salesPerson => {
                salesPersonFilter.innerHTML += `<option value="${salesPerson}">${salesPerson}</option>`;
            });
            console.log('Populated sales person dropdown with', salesPersons.length, 'sales persons');
        }

        // Populate item dropdown
        const itemFilter = safeGetElement('item_filter');
        if (itemFilter) {
            const items = [...new Set(allSalesOrderItems.map(item => item.item_code).filter(i => i))].sort();

            itemFilter.innerHTML = '<option value="">All Items</option>';
            items.forEach(itemCode => {
                const itemData = allSalesOrderItems.find(i => i.item_code === itemCode);
                const itemName = itemData?.item_name || itemCode;
                itemFilter.innerHTML += `<option value="${itemCode}">${itemCode} - ${itemName}</option>`;
            });
            console.log('Populated item dropdown with', items.length, 'items');
        }
    }

    // Function to apply filters
    function applyFilters() {
        if (!checkFrappeAvailability()) {
            return;
        }

        console.log("Applying filters...");

        // Update current filters from DOM
        updateCurrentFiltersFromDOM();
        console.log("Current filters:", currentFilters);

        // Show loading in table
        safeSetContent('sales_order_tbody', 
            '<tr><td colspan="10" style="text-align: center; padding: 20px;">Applying filters...</td></tr>');

        // Start with all sales orders
        let filtered = [...allSalesOrders];

        // Apply customer filter
        if (currentFilters.customer) {
            filtered = filtered.filter(order => order.customer === currentFilters.customer);
        }

        // Apply sales order filter
        if (currentFilters.sales_order) {
            filtered = filtered.filter(order => order.name === currentFilters.sales_order);
        }

        // Apply sales person filter
        if (currentFilters.sales_person) {
            filtered = filtered.filter(order => order.custom_sales_person === currentFilters.sales_person);
        }

        // Apply item filter - filter based on items in the order
        if (currentFilters.item) {
            filtered = filtered.filter(order => {
                return order.items && order.items.some(item => item.item_code === currentFilters.item);
            });
        }

        // Apply date filters
        if (currentFilters.date_from || currentFilters.date_to) {
            filtered = filtered.filter(order => {
                if (!order.delivery_date) return false;

                const orderDate = new Date(order.delivery_date);
                let passesDateFilter = true;

                if (currentFilters.date_from) {
                    const fromDate = new Date(currentFilters.date_from);
                    passesDateFilter = passesDateFilter && orderDate >= fromDate;
                }

                if (currentFilters.date_to) {
                    const toDate = new Date(currentFilters.date_to);
                    passesDateFilter = passesDateFilter && orderDate <= toDate;
                }

                return passesDateFilter;
            });
        }

        filteredSalesOrders = filtered;
        populatePendingInvoiceTable(filteredSalesOrders);
        updateFilterSummary();
        console.log("Filtered sales orders count:", filtered.length);

        if (frappe.show_alert) {
            frappe.show_alert({
                message: `Filter applied. Found ${filtered.length} orders.`,
                indicator: 'green'
            }, 3);
        }
    }

    // Function to clear all filters
    function clearAllFilters() {
        console.log("Clearing all filters...");

        // Reset current filters
        currentFilters = {
            customer: '',
            sales_order: '',
            sales_person: '',
            item: '',
            date_from: '',
            date_to: ''
        };

        // Reset UI inputs
        const customerFilter = safeGetElement('customer_filter');
        const salesOrderFilter = safeGetElement('sales_order_filter');
        const salesPersonFilter = safeGetElement('sales_person_filter');
        const itemFilter = safeGetElement('item_filter');
        const dateFromFilter = safeGetElement('date_from_filter');
        const dateToFilter = safeGetElement('date_to_filter');

        if (customerFilter) customerFilter.value = '';
        if (salesOrderFilter) salesOrderFilter.value = '';
        if (salesPersonFilter) salesPersonFilter.value = '';
        if (itemFilter) itemFilter.value = '';
        if (dateFromFilter) dateFromFilter.value = '';
        if (dateToFilter) dateToFilter.value = '';

        // Show all original data
        filteredSalesOrders = [...allSalesOrders];
        populatePendingInvoiceTable(filteredSalesOrders);
        updateFilterSummary();

        if (frappe.show_alert) {
            frappe.show_alert({
                message: 'All filters cleared',
                indicator: 'blue'
            }, 2);
        }
    }

    // Helper function to update current filters from DOM
    function updateCurrentFiltersFromDOM() {
        const customerFilter = safeGetElement('customer_filter');
        const salesOrderFilter = safeGetElement('sales_order_filter');
        const salesPersonFilter = safeGetElement('sales_person_filter');
        const itemFilter = safeGetElement('item_filter');
        const dateFromFilter = safeGetElement('date_from_filter');
        const dateToFilter = safeGetElement('date_to_filter');

        if (customerFilter) currentFilters.customer = customerFilter.value;
        if (salesOrderFilter) currentFilters.sales_order = salesOrderFilter.value;
        if (salesPersonFilter) currentFilters.sales_person = salesPersonFilter.value;
        if (itemFilter) currentFilters.item = itemFilter.value;
        if (dateFromFilter) currentFilters.date_from = dateFromFilter.value;
        if (dateToFilter) currentFilters.date_to = dateToFilter.value;
    }

    // Function to update filter summary display
    function updateFilterSummary() {
        const summaryElement = safeGetElement('filter_summary');
        if (!summaryElement) return;

        const activeFilters = [];
        if (currentFilters.customer) activeFilters.push(`Customer: ${currentFilters.customer}`);
        if (currentFilters.sales_order) activeFilters.push(`Sales Order: ${currentFilters.sales_order}`);
        if (currentFilters.sales_person) activeFilters.push(`Sales Person: ${currentFilters.sales_person}`);
        if (currentFilters.item) {
            const itemData = allSalesOrderItems.find(i => i.item_code === currentFilters.item);
            const itemName = itemData?.item_name || currentFilters.item;
            activeFilters.push(`Item: ${currentFilters.item} - ${itemName}`);
        }
        if (currentFilters.date_from) {
            let fromDate = currentFilters.date_from;
            if (frappe && frappe.datetime && frappe.datetime.str_to_user) {
                fromDate = frappe.datetime.str_to_user(currentFilters.date_from);
            }
            activeFilters.push(`From: ${fromDate}`);
        }
        if (currentFilters.date_to) {
            let toDate = currentFilters.date_to;
            if (frappe && frappe.datetime && frappe.datetime.str_to_user) {
                toDate = frappe.datetime.str_to_user(currentFilters.date_to);
            }
            activeFilters.push(`To: ${toDate}`);
        }

        if (activeFilters.length > 0) {
            summaryElement.innerHTML = '<strong>Active Filters:</strong> ' + activeFilters.join(' | ');
        } else {
            summaryElement.innerHTML = 'No filters applied - showing all pending invoice orders';
        }
    }

    // Function to format currency using Frappe's formatting
    function format_currency(amount, currency) {
        if (frappe && frappe.format) {
            try {
                return frappe.format(amount, {fieldtype:'Currency'}, {currency: currency});
            } catch(e) {
                console.warn('Error formatting currency:', e);
            }
        }
        // Fallback formatting
        const symbol = currency === 'INR' ? '₹' : (currency || '');
        return `${symbol} ${(amount || 0).toLocaleString(undefined, {minimumFractionDigits: 2})}`;
    }

    // Function to format items display
    function formatItemsDisplay(items) {
        if (!items || items.length === 0) return '-';

        // Show first 2 items with quantities, then count if more
        const displayItems = items.slice(0, 2).map(item => {
            const pendingQty = (item.qty || 0) - (item.billed_qty || 0);
            return `${item.item_code} (${pendingQty.toFixed(2)})`;
        });

        if (items.length > 2) {
            displayItems.push(`+${items.length - 2} more`);
        }

        return displayItems.join('<br>');
    }

    // Function to populate the table with pending invoice data
    function populatePendingInvoiceTable(sales_orders) {
        console.log("Populating table with", sales_orders.length, "orders");

        const tbody = safeGetElement('sales_order_tbody');
        if (!tbody) {
            console.error("Sales order table body not found in root_element");
            return;
        }

        if (sales_orders.length === 0) {
            tbody.innerHTML = "<tr><td colspan='10' class='no-data'>No sales orders found with current filters</td></tr>";
            safeSetStyle('sales_order_table', 'display', 'table');
        } else {
            let tableHTML = "";

            sales_orders.forEach(function (sales_order, orderIndex) {
                // Double-check filtering: only include items that truly have pending amounts
                const allItems = sales_order.items || [];
                const trulyPendingItems = allItems.filter(item => {
                    const pendingAmt = (item.amount || 0) - (item.billed_amt || 0);
                    console.log(`Item ${item.item_code}: amount=${item.amount}, billed_amt=${item.billed_amt}, pending_amt=${pendingAmt}`);
                    return pendingAmt > 0;
                });

                // Update the sales order items to only include truly pending items
                sales_order.items = trulyPendingItems;
                const hasPendingItems = trulyPendingItems.length > 0;

                console.log(`Sales Order ${sales_order.name}: ${trulyPendingItems.length} pending items by amount`);

                // Create main sales order row
                tableHTML += createMainSalesOrderRow(sales_order, orderIndex, hasPendingItems);

                // Create collapsible item rows (initially hidden) - only for items with actual pending amounts
                if (hasPendingItems) {
                    trulyPendingItems.forEach(function(item, itemIndex) {
                        const pendingAmt = (item.amount || 0) - (item.billed_amt || 0);
                        if (pendingAmt > 0) { // Extra safety check
                            tableHTML += createItemRow(sales_order, item, orderIndex, itemIndex);
                        }
                    });
                }
            });

            tbody.innerHTML = tableHTML;
            safeSetStyle('sales_order_table', 'display', 'table');

            // Attach click events to expand/collapse arrows
            attachExpandCollapseEvents();

            console.log("Table populated successfully");
        }

        // Add summary
        addPendingInvoiceSummary(sales_orders);
    }

    // Function to create the main sales order row
    function createMainSalesOrderRow(sales_order, orderIndex, hasPendingItems) {
        // Always recalculate pending items to ensure accuracy
        const pendingItems = (sales_order.items || []).filter(item => {
            const pendingAmt = (item.amount || 0) - (item.billed_amt || 0);
            return pendingAmt > 0;
        });

        const actualPendingCount = pendingItems.length;

        let tableHTML = `<tr class="main-order-row" data-order-index="${orderIndex}">`;

        // Expand/Collapse arrow - only show if there are actual pending items
        if (actualPendingCount > 0) {
            tableHTML += `<td class="expand-cell">
                <span class="expand-arrow" onclick="toggleOrderItems(${orderIndex})" style="cursor: pointer; font-size: 16px; color: #007bff;" title="Click to expand ${actualPendingCount} pending items">
                    ▶
                </span>
            </td>`;
        } else {
            tableHTML += `<td class="expand-cell"></td>`;
        }

        // Sales Order ID with link
        tableHTML += `<td><a href='/app/sales-order/${sales_order.name}' target='_blank'>${sales_order.name}</a></td>`;

        // Customer
        tableHTML += `<td>${sales_order.customer || '-'}</td>`;

        // Sales Person
        tableHTML += `<td>${sales_order.custom_sales_person || '-'}</td>`;

        // Items Summary - only show pending items
        if (actualPendingCount > 0) {
            const pendingItemsText = actualPendingCount === 1 ? 'pending item' : 'pending items';

            const itemSummary = pendingItems.slice(0, 2).map(item => {
                const pendingAmt = (item.amount || 0) - (item.billed_amt || 0);
                return `${item.item_name}`;
            }).join(', ');
            const summary = actualPendingCount > 2 ? `${itemSummary} +${actualPendingCount - 2} more` : itemSummary;
            tableHTML += `<td class="items-summary" style="color: #007bff; cursor: pointer; line-height: 1.2;" onclick="toggleOrderItems(${orderIndex})" title="Click to view ${actualPendingCount} pending items">
                <div style="margin-bottom: 2px;">${summary}</div>
                <small style="color: #666;">(${actualPendingCount} ${pendingItemsText})</small>
            </td>`;
        } else {
            tableHTML += `<td style="color: #28a745; font-style: italic;">All items fully invoiced</td>`;
        }

        // Status with color coding
        let statusColor = "";
        switch(sales_order.status) {
            case "To Deliver and Bill":
                statusColor = "Black";
                break;
            case "To Bill":
                statusColor = "Black";
                break;
            default:
                statusColor = "Black";
        }
        tableHTML += `<td style='color: ${statusColor}; font-weight: bold;'>${sales_order.status}</td>`;

        // Delivery Date with overdue highlighting
        let deliveryDate = '-';
        let deliveryDateColor = "#495057";

        if (sales_order.delivery_date) {
            deliveryDate = sales_order.delivery_date;
            if (frappe && frappe.datetime && frappe.datetime.str_to_user) {
                try {
                    deliveryDate = frappe.datetime.str_to_user(sales_order.delivery_date);
                } catch(e) {
                    console.warn('Error formatting date:', e);
                }
            }

            const today = new Date();
            const dueDate = new Date(sales_order.delivery_date);
            today.setHours(0,0,0,0);
            dueDate.setHours(0,0,0,0);
            if (dueDate < today) {
                deliveryDateColor = "#dc3545"; // Red for overdue
            } else if ((dueDate - today) / (1000 * 60 * 60 * 24) <= 7) {
                deliveryDateColor = "#fd7e14"; // Orange for due soon
            }
        }
        tableHTML += `<td style='color: ${deliveryDateColor}; font-weight: bold;'>${deliveryDate}</td>`;

        // Total Pending Amount - calculate only from actually pending items
        let totalPendingAmount = 0;
        if (actualPendingCount > 0) {
            pendingItems.forEach(item => {
                const itemAmount = item.amount || 0;
                const billedAmount = item.billed_amt || 0;
                const pendingAmount = itemAmount - billedAmount;
                if (pendingAmount > 0) {
                    totalPendingAmount += pendingAmount;
                }
            });
        }
        const formattedPendingAmount = format_currency(totalPendingAmount, sales_order.currency);
        tableHTML += `<td style='color: Black; font-weight: bold; font-size: 14px; text-align: center;'>${formattedPendingAmount}</td>`;

        // Total Pending Quantity - calculate only from actually pending items
        let totalPendingQty = 0;
        if (actualPendingCount > 0) {
            pendingItems.forEach(item => {
                const billedQty = item.billed_qty || 0;
                const totalQty = item.qty || 0;
                const pendingQty = totalQty - billedQty;
                if (pendingQty > 0) {
                    totalPendingQty += pendingQty;
                }
            });
        }
        tableHTML += `<td style='color: Black; font-weight: bold; text-align: center;'>${totalPendingQty.toFixed(2)}</td>`;

        // Action
        tableHTML += `<td><a href='/app/sales-order/${sales_order.name}' class='btn btn-info' target='_blank'>View</a></td>`;

        tableHTML += "</tr>";
        return tableHTML;
    }

    // Function to create item detail rows (initially hidden)
    function createItemRow(sales_order, item, orderIndex, itemIndex) {
        const pendingAmt = (item.amount || 0) - (item.billed_amt || 0);

        // Skip this item if it's fully invoiced by amount
        if (pendingAmt <= 0) {
            return '';
        }

        const totalAmount = item.amount || 0;
        const billedAmount = item.billed_amt || 0;

        let tableHTML = `<tr class="item-row item-row-${orderIndex}" style="display: none; background-color: #f8f9ff;">`;

        // Empty expand cell
        tableHTML += `<td class="expand-cell"></td>`;

        // Empty sales order cell with item indicator
        tableHTML += `<td style="padding-left: 20px; color: #666; font-size: 11px;">${itemIndex + 1}</td>`;

        // Empty customer cell
        tableHTML += `<td></td>`;

        // Empty sales person cell
        tableHTML += `<td></td>`;

        // Item details with amount-based calculations
        const billedPercentage = totalAmount > 0 ? ((billedAmount / totalAmount) * 100).toFixed(1) : 0;
        const pendingPercentage = (100 - billedPercentage).toFixed(1);

        tableHTML += `<td style="padding-left: 15px;">
            <div style="font-size: 11px; color: #666; margin-top: 2px;">${item.item_name || ''}</div>
            <div style="font-size: 10px; color: #888; margin-top: 2px;">
                <span style="color: #28a745;">Total: ${format_currency(totalAmount, sales_order.currency)}</span> | 
                <span style="color: #dc3545;">Pending: ${format_currency(pendingAmt, sales_order.currency)}</span>
            </div>
        </td>`;

        // Empty status cell
        tableHTML += `<td></td>`;

        // Empty delivery date cell
        tableHTML += `<td></td>`;

        // Item pending amount
        const formattedPendingAmount = format_currency(pendingAmt, sales_order.currency);
        tableHTML += `<td style='color: #dc3545; font-weight: bold; font-size: 12px; text-align: center;'>${formattedPendingAmount}</td>`;

        // Item pending quantity (still show qty for reference)
        const pendingQty = (item.qty || 0) - (item.billed_qty || 0);
        tableHTML += `<td style='color: #dc3545; font-weight: bold; text-align: center; font-size: 12px;'>${pendingQty.toFixed(2)}</td>`;

        // Empty action cell
        tableHTML += `<td></td>`;

        tableHTML += "</tr>";
        return tableHTML;
    }

    // Function to attach expand/collapse event listeners
    function attachExpandCollapseEvents() {
        // This function is called after the table is populated
        // The actual toggle function is defined globally below
    }

    // Global function to toggle order items visibility
    window.toggleOrderItems = function(orderIndex) {
        const itemRows = root_element.querySelectorAll(`.item-row-${orderIndex}`);
        const arrow = root_element.querySelector(`[data-order-index="${orderIndex}"] .expand-arrow`);

        if (!arrow) return;

        const isCurrentlyExpanded = arrow.innerHTML === '▼';

        itemRows.forEach(row => {
            if (isCurrentlyExpanded) {
                row.style.display = 'none';
            } else {
                row.style.display = 'table-row';
            }
        });

        // Toggle arrow direction
        arrow.innerHTML = isCurrentlyExpanded ? '▶' : '▼';
        arrow.title = isCurrentlyExpanded ? 'Click to expand items' : 'Click to collapse items';

        console.log(`${isCurrentlyExpanded ? 'Collapsed' : 'Expanded'} items for order index ${orderIndex}`);
    };

    // Function to add summary information
    function addPendingInvoiceSummary(sales_orders) {
        let totalPendingAmount = 0;
        let totalPendingQty = 0;
        let overdueCount = 0;
        let defaultCurrency = 'INR';

        sales_orders.forEach(function(order) {
            const billedPercentage = order.per_billed || 0;
            const pendingAmount = order.grand_total ? 
                (order.grand_total * (100 - billedPercentage)) / 100 : 0;
            totalPendingAmount += pendingAmount;

            const totalQty = order.total_qty || 0;
            const billedQty = (totalQty * billedPercentage) / 100;
            totalPendingQty += (totalQty - billedQty);

            if (order.currency) {
                defaultCurrency = order.currency;
            }

            if (order.delivery_date) {
                const today = new Date();
                const dueDate = new Date(order.delivery_date);
                today.setHours(0,0,0,0);
                dueDate.setHours(0,0,0,0);
                if (dueDate < today) {
                    overdueCount++;
                }
            }
        });
    }

    // Initialize the dashboard when DOM is ready
    function initializeDashboard() {
        if (isInitialized) {
            console.log('Dashboard already initialized');
            return;
        }

        console.log('Initializing dashboard...');

        // Check if root_element is available
        if (typeof root_element === 'undefined') {
            console.error('root_element is not available');
            return;
        }

        console.log('root_element found:', root_element);

        // Wait a bit for DOM to be fully ready
        setTimeout(function() {
            // Attach event listeners
            const applyBtn = safeGetElement('apply_filter_btn');
            const clearBtn = safeGetElement('clear_filter_btn');

            if (applyBtn) {
                applyBtn.addEventListener('click', applyFilters);
                console.log('Apply button event listener attached');
            }

            if (clearBtn) {
                clearBtn.addEventListener('click', clearAllFilters);
                console.log('Clear button event listener attached');
            }

            // Add change event listeners for real-time filter summary updates
            const filterElements = ['customer_filter', 'sales_order_filter', 'sales_person_filter', 'item_filter', 'date_from_filter', 'date_to_filter'];
            filterElements.forEach(id => {
                const element = safeGetElement(id);
                if (element) {
                    element.addEventListener('change', function() {
                        updateCurrentFiltersFromDOM();
                        updateFilterSummary();
                    });
                    console.log(`Change event listener attached for ${id}`);
                }
            });

            isInitialized = true;
            console.log('Dashboard initialized successfully');

            // Load initial data
            fetchAllSalesOrders();
        }, 500); // Wait 500ms for DOM to be fully ready
    }

    // Multiple initialization attempts to handle different loading states
    function attemptInitialization() {
        console.log('Attempting initialization, document state:', document.readyState);

        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', initializeDashboard);
        } else {
            initializeDashboard();
        }

        // Also try after a delay in case DOM isn't fully ready
        setTimeout(initializeDashboard, 1000);
    }

    // Start initialization
    attemptInitialization();

